import { NextResponse } from "next/server";

interface Todo {
  id: string;
  text: string;
  completed: boolean;
  createdAt: number;
}

// In-memory store (resets on server restart — perfect for a simple demo)
let todos: Todo[] = [
  { id: "1", text: "Buy groceries", completed: false, createdAt: Date.now() - 3000 },
  { id: "2", text: "Read a book", completed: true, createdAt: Date.now() - 2000 },
  { id: "3", text: "Walk the dog", completed: false, createdAt: Date.now() - 1000 },
];

let nextId = 4;

/** GET /api/todos — return all todos */
export async function GET() {
  return NextResponse.json({ data: todos });
}

/** POST /api/todos — create a new todo */
export async function POST(request: Request) {
  try {
    const body = await request.json();
    const text = typeof body.text === "string" ? body.text.trim() : "";

    if (!text) {
      return NextResponse.json(
        { error: { code: "VALIDATION_ERROR", message: "Todo text is required" } },
        { status: 422 }
      );
    }

    const todo: Todo = {
      id: String(nextId++),
      text,
      completed: false,
      createdAt: Date.now(),
    };

    todos.push(todo);

    return NextResponse.json({ data: todo }, { status: 201 });
  } catch {
    return NextResponse.json(
      { error: { code: "INTERNAL_ERROR", message: "Failed to create todo" } },
      { status: 500 }
    );
  }
}
