import { NextResponse } from "next/server";

interface Todo {
  id: string;
  text: string;
  completed: boolean;
  createdAt: number;
}

// Reference the same in-memory store — in a real app this would be a database
// For this simple demo, we use a global variable approach
declare global {
  var __todos: Todo[] | undefined;
  var __nextId: number | undefined;
}

function getStore(): { todos: Todo[]; nextId: number } {
  if (!globalThis.__todos) {
    globalThis.__todos = [
      { id: "1", text: "Buy groceries", completed: false, createdAt: Date.now() - 3000 },
      { id: "2", text: "Read a book", completed: true, createdAt: Date.now() - 2000 },
      { id: "3", text: "Walk the dog", completed: false, createdAt: Date.now() - 1000 },
    ];
    globalThis.__nextId = 4;
  }
  return { todos: globalThis.__todos, nextId: globalThis.__nextId! };
}

type RouteContext = { params: Promise<{ id: string }> };

/** PATCH /api/todos/:id — update a todo (toggle completed or edit text) */
export async function PATCH(request: Request, context: RouteContext) {
  try {
    const { id } = await context.params;
    const store = getStore();
    const idx = store.todos.findIndex((t) => t.id === id);

    if (idx === -1) {
      return NextResponse.json(
        { error: { code: "NOT_FOUND", message: "Todo not found" } },
        { status: 404 }
      );
    }

    const body = await request.json();

    if (typeof body.completed === "boolean") {
      store.todos[idx].completed = body.completed;
    }
    if (typeof body.text === "string" && body.text.trim()) {
      store.todos[idx].text = body.text.trim();
    }

    return NextResponse.json({ data: store.todos[idx] });
  } catch {
    return NextResponse.json(
      { error: { code: "INTERNAL_ERROR", message: "Failed to update todo" } },
      { status: 500 }
    );
  }
}

/** DELETE /api/todos/:id — delete a todo */
export async function DELETE(_request: Request, context: RouteContext) {
  try {
    const { id } = await context.params;
    const store = getStore();
    const idx = store.todos.findIndex((t) => t.id === id);

    if (idx === -1) {
      return NextResponse.json(
        { error: { code: "NOT_FOUND", message: "Todo not found" } },
        { status: 404 }
      );
    }

    store.todos.splice(idx, 1);

    return new NextResponse(null, { status: 204 });
  } catch {
    return NextResponse.json(
      { error: { code: "INTERNAL_ERROR", message: "Failed to delete todo" } },
      { status: 500 }
    );
  }
}
